import java.util.*;
class Customer{
    public static int idCounter=1;
    private final int customerId;
    private int revenue;
    private Customer referredBy;

    public Customer(int revenue){
       this.revenue= revenue;
       this.customerId = idCounter++;
    }
    int getId() { return customerId; }
    Customer getReferredBy() { return referredBy; }
    void setReferredBy(Customer id) {
        this.referredBy = id;
    }
    void addRevenue(int revenue ){
        this.revenue+=revenue;
    }
    int getRevenue() {return this.revenue;}

}
class CustomerManager{
    private HashMap<Integer, Customer> map ;
    public CustomerManager(){
        map = new HashMap<>();
    }
    public Customer addCustomer(int revenue){
        Customer c = new Customer(revenue);
        map.put(c.getId(), c);
        return c;
    }

    public Customer addCustomer(int revenue, int referredById){
        Customer c = new Customer(revenue);
        if(map.get(referredById)!=null){
            c.setReferredBy(map.get(referredById));
            map.get(referredById).addRevenue(revenue);
        }
        map.put(c.getId(), c);
        return c;
    }

    List<Customer> getTopKCustomerWithGreaterValue(int k , int value){
        List<Customer> res = new ArrayList<>();
        PriorityQueue<Customer> q = new PriorityQueue<>((c1,c2) -> c2.getRevenue()-c1.getRevenue());
        for(Customer c : map.values()){
            //System.out.println(c.getId()+ " "+c.getRevenue());
            if(c.getRevenue() > value){
                q.add(c);
                if(q.size()>k) q.poll();
            }
        }
        while(!q.isEmpty()){
            res.add(q.poll());
        }
        Collections.reverse(res);
        return res;
    }
}
class Main {
    public static void main(String[] args) {
       CustomerManager cm = new CustomerManager();
       cm.addCustomer(100);
       cm.addCustomer(50, 1);
       cm.addCustomer(30, 2);
       cm.addCustomer(100);
       cm.addCustomer(200);
       cm.addCustomer(130, 3);
       List<Customer> res = cm.getTopKCustomerWithGreaterValue(3, 90);

       res.forEach(c -> System.out.println(c.getId()+ " " + c.getRevenue()));
    }
}




from sortedcontainers import SortedDict, SortedSet
class CustomerRevenueHandler:
    def __init__(self):
        self.d = SortedDict({})
        self.revenueMapping = SortedDict({})

    def addCustomer(self, revenue):
        id = len(self.d)
        self.d[id] = revenue;

        if(revenue not in self.revenueMapping):
            self.revenueMapping[revenue] = SortedSet()
        self.revenueMapping[revenue].add(id)

    def addCustomerWithReferral(self, revenue, referredBy):
        self.addCustomer(revenue)

        prevRevenue = self.d[referredBy]
        self.d[referredBy] += revenue

        self.revenueMapping[prevRevenue].remove(referredBy)

        if(len(self.revenueMapping[prevRevenue])==0):
            del self.revenueMapping[prevRevenue]

        newRevenue = self.d[referredBy]
        if(newRevenue not in self.revenueMapping):
            self.revenueMapping[newRevenue] = SortedSet()
        self.revenueMapping[newRevenue].add(referredBy)

    def getKCustomersWithRevenueGreaterThanValue(self, totalCount , value):
        result = []

        for k in self.revenueMapping.irange(minimum = value):
            v = self.revenueMapping[k];
            if k >= value:
                index = 0
                while(len(result) < totalCount and  index < len(v)):
                    result.append((k,v[index]))
                    index += 1
            if(len(result)>= totalCount):
                break

        return result




